<script setup lang="ts">
import { computed,onMounted,ref,watch } from 'vue'
import { useRoute } from 'vue-router'
import MesLayout from '@/layouts/MesLayout.vue'
import { get,post } from '@/api/client'
import SopModelViewer from '@/components/SopModelViewer.vue'
type Step={id:number;stepNo:number;stepName:string;instruction?:string;minStaySeconds?:number;confirmRequired?:boolean;parameterRequired?:boolean;photoRequired?:boolean}; type Record={stepId:number;confirmedAt?:string;result?:string};type Package={document:{id?:number;sopCode:string;sopName:string;currentVersionId?:number};version:{id?:number;versionNo:string;status?:string;modelVersionId?:number};snapshot:{id:number;modelVersionId?:number};execution:{status:string;startedAt?:string};steps:Step[];stepRecords:Record[]};type Execution={id:number;taskId:number;versionId:number;status:string;executedAt?:string};type Document={id:number;sopCode:string;sopName:string;currentVersionId?:number};type DocumentDetail={document:Document;versions:Array<{id:number;versionNo:string;status?:string;modelVersionId?:number}>}
const route=useRoute(),taskId=computed(()=>Number(route.query.taskId||0)),documents=ref<Document[]>([]),selectedDocumentId=ref<number|undefined>(),data=ref<Package|null>(null),loading=ref(false),error=ref(''),busy=ref<number|null>(null),parameter=ref(''),photoAttachmentId=ref(''),activeStep=ref<Step|null>(null),validation=ref(''),executions=ref<Execution[]>([]),showRecords=ref(false)
async function open(id=taskId.value){if(!id){error.value='请输入生产任务 ID';return};loading.value=true;error.value='';try{data.value=await get<Package>(`/production/sop/tasks/${id}`)}catch(e){error.value=e instanceof Error?e.message:'SOP 任务打开失败'}finally{loading.value=false}}
async function loadDocuments(){loading.value=true;error.value='';try{documents.value=await get<Document[]>('/production/sop/documents',{status:'ENABLED'});if(documents.value.length){selectedDocumentId.value=selectedDocumentId.value||documents.value[0].id;await browse(selectedDocumentId.value)}}catch(e){error.value=e instanceof Error?e.message:'SOP 文档加载失败'}finally{loading.value=false}}
async function browse(documentId=selectedDocumentId.value){if(!documentId)return;loading.value=true;error.value='';try{const detail=await get<DocumentDetail>(`/production/sop/documents/${documentId}`);const version=detail.versions.find(item=>item.id===detail.document.currentVersionId)||detail.versions.find(item=>item.status==='EFFECTIVE')||detail.versions[0];if(!version)throw new Error('该 SOP 文档尚无可查看版本');const steps=await get<Step[]>(`/production/sop/versions/${version.id}/steps`);data.value={document:detail.document,version,snapshot:{id:0,modelVersionId:version.modelVersionId},execution:{status:'BROWSE'},steps,stepRecords:[]};activeStep.value=steps[0]||null}catch(e){error.value=e instanceof Error?e.message:'SOP 打开失败'}finally{loading.value=false}}
function record(step:Step){return data.value?.stepRecords.find(item=>item.stepId===step.id)};function done(step:Step){return Boolean(record(step)?.confirmedAt)}
async function view(step:Step){if(!data.value||done(step))return;activeStep.value=step;if(!data.value.snapshot.id)return;try{await post(`/production/sop/snapshots/${data.value.snapshot.id}/steps/${step.id}/view`)}catch(e){error.value=e instanceof Error?e.message:'记录步骤查看失败'}}
async function confirmStep(step:Step){if(!data.value)return;busy.value=step.id;error.value='';try{await post(`/production/sop/snapshots/${data.value.snapshot.id}/steps/${step.id}/confirm`,{operatorId:null,parameterJson:step.parameterRequired?parameter.value||null:null,photoAttachmentId:step.photoRequired?Number(photoAttachmentId.value)||null:null,result:'CONFIRMED',idempotencyKey:`web-${data.value.snapshot.id}-${step.id}`});await open()}catch(e){error.value=e instanceof Error?e.message:'步骤确认失败'}finally{busy.value=null}}
async function validate(){if(!taskId.value)return;try{const result=await get<{passed:boolean;pendingRequiredSteps:number;messages:string[]}>(`/production/sop/tasks/${taskId.value}/report-validation`);validation.value=result.passed?'可进行报工':`不可报工：${result.messages.join('；')||`尚有 ${result.pendingRequiredSteps} 个必填步骤`}`}catch(e){error.value=e instanceof Error?e.message:'报工校验失败'}}
async function loadRecords(){try{executions.value=await get<Execution[]>('/production/sop/executions',{taskId:taskId.value||undefined});showRecords.value=true}catch(e){error.value=e instanceof Error?e.message:'执行记录加载失败'}}
onMounted(()=>{if(taskId.value)void open();else void loadDocuments()});watch(taskId,()=>{if(taskId.value)void open()})
</script>
<template><MesLayout active="sopexec"><header class="app-header"><div class="header-breadcrumb"><span>电子 SOP</span><span class="bc-sep">/</span><span class="bc-current">执行终端</span></div><div class="header-actions"><button class="btn btn-secondary btn-sm" @click="loadRecords">执行记录</button><span class="user-avatar">张</span></div></header><main class="app-main"><h1 class="page-title">SOP 执行终端</h1><div v-if="!taskId" class="card mb-5"><div class="search-bar" style="margin-bottom:0"><div class="form-group" style="min-width:320px"><label class="form-label">选择 SOP 文档</label><select v-model="selectedDocumentId" class="form-select" :disabled="loading" @change="browse()"><option v-for="doc in documents" :key="doc.id" :value="doc.id">{{doc.sopCode}} · {{doc.sopName}}</option></select></div><button class="btn btn-secondary btn-sm" style="align-self:flex-end" :disabled="loading" @click="loadDocuments">刷新</button></div><p class="text-muted mt-4">当前为 SOP 浏览模式；从生产任务进入时，才可以确认步骤与进行报工校验。</p></div><div v-if="error" class="alert alert-error mb-5"><span class="alert-icon">!</span>{{error}}</div><div v-if="data" class="execution-grid"><section class="card"><div class="card-header"><div><h2 class="card-title">{{data.document.sopName}}</h2><span class="text-muted">{{data.document.sopCode}} · {{data.version.versionNo}}</span></div><span class="badge badge-status-ok"><span class="badge-dot"></span>{{data.execution.status==='BROWSE'?'浏览模式':data.execution.status}}</span></div><div class="step-list"><article v-for="step in data.steps" :key="step.id" class="step-card" :class="{done:done(step),active:activeStep?.id===step.id}" @click="view(step)"><div class="step-no">{{done(step)?'✓':step.stepNo}}</div><div class="step-content"><strong>{{step.stepName}}</strong><p>{{step.instruction||'暂无作业说明'}}</p><small v-if="step.minStaySeconds">最短查看 {{step.minStaySeconds}} 秒</small></div><button v-if="taskId&&!done(step)" class="btn btn-primary btn-sm" :disabled="busy===step.id" @click.stop="confirmStep(step)">{{busy===step.id?'确认中...':'确认步骤'}}</button><span v-else-if="done(step)" class="text-muted">已确认</span></article></div><div v-if="taskId&&activeStep" class="execution-inputs"><div v-if="activeStep.parameterRequired" class="form-group"><label class="form-label">步骤参数</label><textarea v-model="parameter" class="form-input" rows="2" placeholder='例如：{"torque":"4.0"}'></textarea></div><div v-if="activeStep.photoRequired" class="form-group"><label class="form-label">照片附件 ID</label><input v-model="photoAttachmentId" class="form-input" inputmode="numeric" placeholder="先在版本附件中上传照片后填写 ID"></div></div></section><aside class="execution-side"><section class="card"><div class="card-header"><h2 class="card-title">{{taskId?'执行信息':'SOP 信息'}}</h2></div><table class="data-table" style="border:none"><tbody><tr v-if="taskId"><td>任务</td><td>{{route.query.taskNo||taskId}}</td></tr><tr v-if="taskId"><td>开始时间</td><td>{{data.execution.startedAt?.replace('T',' ')||'-'}}</td></tr><tr><td>{{taskId?'完成步骤':'SOP 步骤'}}</td><td>{{data.stepRecords.filter(item=>item.confirmedAt).length}} / {{data.steps.length}}</td></tr><tr v-if="taskId"><td>快照 ID</td><td class="cell-mono">{{data.snapshot.id}}</td></tr><tr v-else><td>版本状态</td><td>{{data.version.status||'-'}}</td></tr></tbody></table><button v-if="taskId" class="btn btn-secondary btn-sm" @click="validate">报工校验</button><p v-if="validation" class="text-muted mt-4">{{validation}}</p></section><section class="card"><div class="card-header"><h2 class="card-title">3D 作业模型</h2></div><SopModelViewer :model-version-id="data.snapshot.modelVersionId" /></section></aside></div><section v-if="showRecords" class="card mt-5"><div class="card-header"><h2 class="card-title">SOP 执行记录</h2></div><table class="data-table"><thead><tr><th>执行 ID</th><th>任务</th><th>版本</th><th>状态</th><th>执行时间</th></tr></thead><tbody><tr v-if="!executions.length"><td colspan="5">暂无执行记录</td></tr><tr v-for="item in executions" :key="item.id"><td class="cell-mono">{{item.id}}</td><td>{{item.taskId}}</td><td>{{item.versionId}}</td><td>{{item.status}}</td><td>{{item.executedAt?.replace('T',' ')||'-'}}</td></tr></tbody></table></section></main><footer class="app-statusbar"><span class="statusbar-item"><span class="dot ok"></span>{{taskId?'SOP 执行中':'SOP 浏览模式'}}</span></footer></MesLayout></template>
<style scoped>.execution-grid{display:grid;grid-template-columns:minmax(0,1fr) 330px;gap:20px}.execution-side{display:grid;gap:18px;align-content:start}.step-list{display:grid;gap:10px}.step-card{display:flex;align-items:flex-start;gap:14px;padding:14px;border:1px solid var(--color-border,#e5e7eb);border-radius:6px;cursor:pointer}.step-card.active{border-color:#3b82f6}.step-card.done{background:#f0fdf4;border-color:#bbf7d0}.step-no{width:27px;height:27px;border-radius:50%;display:grid;place-items:center;flex:none;background:#e5e7eb;font-weight:700}.done .step-no{background:#16a34a;color:#fff}.step-content{flex:1}.step-content p{margin:5px 0;color:var(--color-text-muted,#667085);font-size:13px}.step-content small{color:var(--color-text-muted,#667085)}.execution-inputs{margin-top:18px}@media(max-width:900px){.execution-grid{grid-template-columns:1fr}}</style>
